function closeSuggestionBox(id){const el=document.getElementById(id+'-suggestions'); if(el) el.remove();}
function normalizeAirportValue(input){if(!input)return; const v=input.value.trim().toUpperCase(); if(CODE_MAP[v]) input.value=CODE_MAP[v];}
function attachAutocomplete(id){const input=document.getElementById(id); if(!input)return; input.addEventListener('input',()=>{closeSuggestionBox(id); const v=input.value.trim().toLowerCase(); if(!v)return; const m=AIRPORTS.filter(x=>x.toLowerCase().includes(v)).slice(0,12); if(!m.length)return; const box=document.createElement('div'); box.className='suggestions'; box.id=id+'-suggestions'; m.forEach(match=>{const b=document.createElement('button'); b.type='button'; b.textContent=match; b.onclick=()=>{input.value=match; closeSuggestionBox(id);}; box.appendChild(b);}); input.parentNode.appendChild(box);}); input.addEventListener('blur',()=>{normalizeAirportValue(input); setTimeout(()=>closeSuggestionBox(id),120);});}
function markField(id,outId,valid,msg){const wrap=document.getElementById(id)?.closest('.field'); const out=document.getElementById(outId); if(!wrap||!out)return; wrap.classList.remove('valid','invalid'); wrap.classList.add(valid?'valid':'invalid'); out.className='validation '+(valid?'success':'error'); out.textContent=msg;}
function validateEmailField(){const e=document.getElementById('email'); const h=document.getElementById('email_status'); if(!e||!h)return true; const v=e.value.trim(); const ok=/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v); h.value=ok?'valid':'invalid'; if(!v){markField('email','email-validation',false,'Email is missing and will be flagged as invalid.'); return false;} if(!ok){markField('email','email-validation',false,'Email format looks invalid. The request can still be submitted and flagged.'); return false;} markField('email','email-validation',true,'Email looks valid.'); return true;}
function validatePhoneField(){const e=document.getElementById('phone'); const h=document.getElementById('phone_status'); if(!e||!h)return true; const v=e.value.trim(); const ok=/^\+?[0-9\s\-()](7, 20)$/.test(v); h.value=ok?'valid':'invalid'; if(!v){markField('phone','phone-validation',false,'Phone number is missing and will be flagged as invalid.'); return false;} if(!ok){markField('phone','phone-validation',false,'Phone format looks invalid. The request can still be submitted and flagged.'); return false;} markField('phone','phone-validation',true,'Phone number looks valid.'); return true;}
function updateBudgetOptions(){const cabin=document.getElementById('cabin'); const budget=document.getElementById('budget'); if(!cabin||!budget)return; const ranges={"Premium Economy":["$1,200 – $2,000","$2,000 – $3,000","$3,000 – $4,000"],"Business":["$3,000 – $6,000","$6,000 – $10,000","$10,000 – $15,000"],"First Class":["$8,000 – $12,000","$12,000 – $18,000","$18,000 – $25,000+"]}; budget.innerHTML=(ranges[cabin.value]||[]).map(x=>`<option value="${x}">${x}</option>`).join('');}
function syncConsentFields(){validateEmailField(); validatePhoneField(); const d=document.getElementById('departure'); const r=document.getElementById('return'); if(d&&r&&d.value&&r.value&&r.value<d.value){alert('Return date cannot be earlier than departure date.'); return false;} return true;}
function showCookiePopup(){document.getElementById('cookie-overlay')?.classList.add('show'); document.getElementById('cookie-modal')?.classList.add('show');}
function hideCookiePopup(){document.getElementById('cookie-overlay')?.classList.remove('show'); document.getElementById('cookie-modal')?.classList.remove('show');}
function saveCookieChoice(choice){const a=document.getElementById('cookie-analytics'); localStorage.setItem('luxaeris_cookie_choice',JSON.stringify({choice,analytics:a?a.checked:false,savedAt:new Date().toISOString()})); hideCookiePopup();}
document.addEventListener('DOMContentLoaded',()=>{attachAutocomplete('origin'); attachAutocomplete('destination'); const d=document.getElementById('departure'); const r=document.getElementById('return'); const today=new Date(); const max=new Date(); max.setDate(today.getDate()+364); const fmt=x=>x.toISOString().split('T')[0]; if(d&&r){d.min=fmt(today); d.max=fmt(max); r.min=fmt(today); r.max=fmt(max); d.addEventListener('change',()=>{if(d.value) r.min=d.value;});} document.getElementById('email')?.addEventListener('blur',validateEmailField); document.getElementById('phone')?.addEventListener('blur',validatePhoneField); document.getElementById('cabin')?.addEventListener('change',updateBudgetOptions); updateBudgetOptions(); if(!localStorage.getItem('luxaeris_cookie_choice')) showCookiePopup(); document.getElementById('cookie-accept')?.addEventListener('click',()=>saveCookieChoice('accept_all')); document.getElementById('cookie-reject')?.addEventListener('click',()=>saveCookieChoice('essential_only')); document.getElementById('cookie-save')?.addEventListener('click',()=>saveCookieChoice('custom')); document.getElementById('cookie-manage')?.addEventListener('click',()=>{const p=document.getElementById('cookie-preferences'); if(p) p.hidden=!p.hidden;});});
